func solve(n: Int64, edges: Array<Array<Int64>>, label: String) -> Int64 {
    let n_i = Int(n)
    var adj = Array(repeating: [Int](), count: n_i)
    for e in edges {
        let u = Int(e[0])
        let v = Int(e[1])
        if u == v { continue }
        adj[u].append(v)
        adj[v].append(u)
    }

    let mask_size = 1 << n_i
    var dp = Array(repeating: Array(repeating: Array(repeating: -1, count: n_i), count: n_i), count: mask_size)

    for u in 0..<n_i {
        let mask = 1 << u
        dp[mask][u][u] = 1
    }

    for u in 0..<n_i {
        for v in adj[u] {
            if u < v && label.charAt(u) == label.charAt(v) {
                let mask = (1 << u) | (1 << v)
                dp[mask][u][v] = 2
            }
        }
    }

    var ans = 1
    for mask in 0..<mask_size {
        for u in 0..<n_i {
            for v in u..<n_i {
                if dp[mask][u][v] == -1 { continue }
                if dp[mask][u][v] > ans {
                    ans = dp[mask][u][v]
                }
                for x in adj[u] {
                    if mask & (1 << x) != 0 { continue }
                    for y in adj[v] {
                        if mask & (1 << y) != 0 { continue }
                        if x == y { continue }
                        if label.charAt(x) != label.charAt(y) { continue }
                        let new_mask = mask | (1 << x) | (1 << y)
                        let a = min(x, y)
                        let b = max(x, y)
                        let new_val = dp[mask][u][v] + 2
                        if new_val > dp[new_mask][a][b] {
                            dp[new_mask][a][b] = new_val
                        }
                    }
                }
            }
        }
    }

    return Int64(ans)
}

