func solve(n: Int64, edges: Array<Array<Int64>>, label: String): Int64 {
    int numNodes = n.toInt()
    vector<vector<int>> g(numNodes, vector<int>())
    for edge in edges {
        int u = edge[0].toInt()
        int v = edge[1].toInt()
        g[u].push_back(v)
        g[v].push_back(u)
    }
    if (numNodes == 0) {
        return 0
    }
    vector<vector<vector<bool>>> dp(1 << numNodes, vector<vector<bool>>(numNodes, vector<bool>(numNodes, false)))
    int best = 1
    for (int u = 0; u < numNodes; u++) {
        int mask = 1 << u
        dp[mask][u][u] = true
    }
    for (int mask = 1; mask < (1 << numNodes); mask++) {
        for (int u = 0; u < numNodes; u++) {
            if ((mask & (1 << u)) == 0) continue
            for (int v = 0; v < numNodes; v++) {
                if ((mask & (1 << v)) == 0) continue
                if (dp[mask][u][v]) {
                    int cnt = 0
                    int temp = mask
                    while (temp > 0) {
                        cnt += temp & 1
                        temp >>= 1
                    }
                    if (cnt > best) best = cnt
                    for (int w in g[u]) {
                        if (mask & (1 << w)) continue
                        int new_mask = mask | (1 << w)
                        if (label[w] == label[v]) {
                            if (!dp[new_mask][w][v]) {
                                dp[new_mask][w][v] = true
                            }
