func solve(n: Int64, edges: Array<Array<Int64>>, label: String) -> Int64 {
    let nodeCount = Int(n)
    let totalMasks = 1 << nodeCount
    var dp = Array(repeating: Array(repeating: Array(repeating: false, count: nodeCount), count: nodeCount), count: totalMasks)
    var parent = Array(repeating: Array(repeating: Array(repeating: (-1, -1), count: nodeCount), count: nodeCount), count: totalMasks)
    var adj = Array(repeating: [Int](), count: nodeCount)

    for edge in edges {
        let u = Int(edge[0])
        let v = Int(edge[1])
        if u != v {
            adj[u].append(v)
            adj[v].append(u)
        }
    }

    for i in 0..<nodeCount {
        let mask = 1 << i
        dp[mask][i][i] = true
    }

    for mask in 0..<totalMasks {
        for i in 0..<nodeCount {
            if (mask & (1 << i)) == 0 { continue }
            for j in 0..<nodeCount {
                if (mask & (1 << j)) == 0 { continue }
                if i == j {
                    if mask == (1 << i) {
                        continue
                    } else {
                        continue
                    }
                }
                if dp[mask][i][j] {
                    continue
                }
                let maskWithoutJ = mask & ~(1 << j)
                if maskWithoutJ != mask && (maskWithoutJ & (1 << i)) != 0 {
                    for k in adj[j] {
                        if k < 0 || k >= nodeCount || (maskWithoutJ & (1 << k)) == 0 {
                            continue
                        }
                        if dp[maskWithoutJ][i][k] {
                            dp[mask][i][j] = true
                            parent[mask][i][j] = (k, 0)
                            break
                        }
                    }
                }
                if dp[mask][i][j] {
                    continue
                }
                let maskWithoutI = mask & ~(1 << i)
                if maskWithoutI != mask && (maskWithoutI & (1 << j)) != 0 {
                    for k in adj[i] {
                        if k < 0 || k >= nodeCount || (maskWithoutI & (1 << k)) == 0 {
                            continue
                        }
                        if dp[maskWithoutI][k][j] {
                            dp[mask][i][j] = true
                            parent[mask][i][j] = (k, 1)
                            break
                        }
                    }
                }
            }
        }
    }

    var bestLength: Int64 = 1
    for mask in 0..<totalMasks {
        for i in 0..<nodeCount {
            for j in 0..<nodeCount {
                if !dp[mask][i][j] {
                    continue
                }
                let count = mask.nonzeroBitCount
                var currentMask = mask
                var currentI = i
                var currentJ = j
                var path = [Int]()
                var stack = [(mask: Int, i: Int, j: Int, at: Int)]()
                stack.append((mask: currentMask, i: currentI, j: currentJ, at: -1))
                while let top = stack.last {
                    let (curMask, ii, jj, at) = top
                    if (curMask & -curMask) == curMask {
                        let singleIndex = curMask.trailingZeroBitCount
                        if at == -1 {
                            path.append(singleIndex)
                        }
                        stack.removeLast()
                        continue
                    }
                    if at == -1 {
                        let (k, mode) = parent[curMask][ii][jj]
                        if mode == 0 {
                            stack[stack.count-1] = (curMask, ii, jj, 0)
                            stack.append((curMask & ~(1<<jj), ii, k, -1))
                        } else if mode == 1 {
                            stack[stack.count-1] = (curMask, ii, jj, 1)
                            stack.append((curMask & ~(1<<ii), k, jj, -1))
                        } else {
                            stack.removeLast()
                        }
                    } else {
                        if at == 0 {
                            path.append(jj)
                        } else if at == 1 {
                            path.insert(ii, at: 0)
                        }
                        stack.removeLast()
                    }
                }
                var s = ""
                for node in path {
                    let index = label.index(label.startIndex, offsetBy: node)
                    s.append(label[index])
                }
                if s == String(s.reversed()) {
                    if Int64(count) > bestLength {
                        bestLength = Int64(count)
                    }
                }
            }
        }
    }
    return bestLength
}
